import React from 'react';
import Slider from 'react-slick';

const MySlider = () => {
  const settings = {
    dots: true,
    arrows: true,
    // Resto de opciones del slider
    prevArrow: <CustomPrevArrow />,
    nextArrow: <CustomNextArrow />,
  };

  function CustomPrevArrow({ onClick }) {
    return (
      <div onClick={onClick} style={{ color: 'red' }}>
        Prev
      </div>
    );
  }

  function CustomNextArrow({ onClick }) {
    return (
      <div onClick={onClick} style={{ color: 'blue' }}>
        Next
      </div>
    );
  }

  return (
    <Slider {...settings}>
      <div>
        <h3>Slide 1</h3>
      </div>
      <div>
        <h3>Slide 2</h3>
      </div>
      <div>
        <h3>Slide 3</h3>
      </div>
    </Slider>
  );
};

export default MiSlider;
